@namespace sv_f962de40798645ddbdf794ff630461ae.Components.Pages.Board

<div class="task-card">
    <h4>@Task.Title</h4>
    <p class="assignee">@Task.Assignee</p>
    <span class="priority-badge @GetPriorityClass()">@Task.Priority</span>
    <span class="due-date">@Task.DueDate.ToString("MMM dd")</span>
    <div class="card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="() => OnMoveLeft.InvokeAsync(Task)">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="() => OnMoveRight.InvokeAsync(Task)">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string GetPriorityClass() => Task.Priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };
}

@namespace sv_f962de40798645ddbdf794ff630461ae.Components.Pages.Board

<div class="add-task-form">
    <input type="text" placeholder="Title" @bind="title" />
    <input type="text" placeholder="Assignee" @bind="assignee" />
    <select @bind="priority">
        <option value="High">High</option>
        <option value="Medium">Medium</option>
        <option value="Low">Low</option>
    </select>
    <input type="date" @bind="dueDate" />
    <div class="form-actions">
        <button class="btn-save" @onclick="Save">Save</button>
        <button class="btn-cancel" @onclick="Cancel">Cancel</button>
    </div>
</div>

@code {
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private async Task Save()
    {
        if (!string.IsNullOrWhiteSpace(title))
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
            title = "";
            assignee = "";
            priority = "Medium";
            dueDate = DateTime.Today.AddDays(7);
        }
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@namespace sv_f962de40798645ddbdf794ff630461ae.Components.Pages.Board

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName <span class="task-count">(@Tasks.Count)</span></h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    <div class="column-footer">
        @if (showForm)
        {
            <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
        }
        else
        {
            <button class="btn-add" @onclick="() => showForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
        showForm = false;
    }
}

@namespace sv_f962de40798645ddbdf794ff630461ae.Components.Pages.Board

<div class="board-stats">
    <div class="stat">
        <span class="stat-label">Total</span>
        <span class="stat-value">@Total</span>
    </div>
    <div class="stat">
        <span class="stat-label">To Do</span>
        <span class="stat-value">@TodoCount</span>
    </div>
    <div class="stat">
        <span class="stat-label">In Progress</span>
        <span class="stat-value">@InProgressCount</span>
    </div>
    <div class="stat">
        <span class="stat-label">Done</span>
        <span class="stat-value">@DoneCount</span>
    </div>
    <div class="stat stat-overdue">
        <span class="stat-label">Overdue</span>
        <span class="stat-value">@OverdueCount</span>
    </div>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int TodoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@namespace sv_f962de40798645ddbdf794ff630461ae.Components.Pages.Board

<div class="task-search-bar">
    <input type="text" placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

