arguments.new_str:
@code {
    private const string StatusTodo = "To Do";
    private const string StatusInProgress = "In Progress";
    private const string StatusDone = "Done";

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == StatusTodo).ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == StatusInProgress).ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == StatusDone).ToList();
    private int overdueCount => allTasks.Count(t => t.DueDate < DateTime.Today);

    private List<TaskItem> filteredTodo => FilterBySearch(todoTasks);
    private List<TaskItem> filteredInProgress => FilterBySearch(inProgressTasks);
    private List<TaskItem> filteredDone => FilterBySearch(doneTasks);

    private List<TaskItem> FilterBySearch(List<TaskItem> tasks) =>
        string.IsNullOrEmpty(searchTerm)
            ? tasks
            : tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private void HandleSearch(string term)
    {
        searchTerm = term;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

